/**
 * Property Panel Component
 * Edits selected room properties with auto-save
 */

import React, { useState, useEffect } from 'react';
import useWorldBuilderStore from '../store/store.js';

const ROOM_FLAG_OPTIONS = [
  { letter: 'A', label: 'Dark' },
  { letter: 'C', label: 'No Mob' },
  { letter: 'D', label: 'Indoors' },
  { letter: 'J', label: 'Private' },
  { letter: 'K', label: 'Safe' },
  { letter: 'L', label: 'Solitary' },
  { letter: 'M', label: 'Pet Shop' },
  { letter: 'N', label: 'No Recall' },
  { letter: 'O', label: 'Imp Only' },
  { letter: 'P', label: 'Gods Only' },
  { letter: 'Q', label: 'Heroes Only' },
  { letter: 'R', label: 'Newbies Only' },
  { letter: 'S', label: 'Law' },
  { letter: 'T', label: 'Nowhere' },
];

const KNOWN_FLAG_SET = new Set(ROOM_FLAG_OPTIONS.map((option) => option.letter));

const SECTOR_OPTIONS = [
  { value: '0', label: 'Inside' },
  { value: '1', label: 'City' },
  { value: '2', label: 'Field' },
  { value: '3', label: 'Forest' },
  { value: '4', label: 'Hills' },
  { value: '5', label: 'Mountain' },
  { value: '6', label: 'Water (Swim)' },
  { value: '7', label: 'Water (No Swim)' },
  { value: '8', label: 'Unused' },
  { value: '9', label: 'Air' },
  { value: '10', label: 'Desert' },
];

function parseRawRoomFlags(rawRoomFlags) {
  const normalized = (rawRoomFlags || '0 0 0').trim();
  const parts = normalized.split(/\s+/);

  const compatibilitySlot = parts[0] || '0';
  const flagsToken = parts[1] || '0';
  const sectorType = parts[2] || '0';
  const letters = flagsToken === '0' ? '' : flagsToken.toUpperCase().replace(/[^A-Z]/g, '');

  const knownFlags = [];
  const customLetters = [];

  letters.split('').forEach((letter) => {
    if (KNOWN_FLAG_SET.has(letter)) {
      if (!knownFlags.includes(letter)) {
        knownFlags.push(letter);
      }
      return;
    }
    if (!customLetters.includes(letter)) {
      customLetters.push(letter);
    }
  });

  return {
    compatibilitySlot,
    knownFlags,
    customLetters: customLetters.join(''),
    sectorType,
  };
}

function composeRawRoomFlags(editorState) {
  const compatibilitySlot = (editorState.compatibilitySlot || '0').trim() || '0';
  const known = [...(editorState.knownFlags || [])].map((letter) => letter.toUpperCase());
  const custom = (editorState.customLetters || '').toUpperCase().replace(/[^A-Z]/g, '').split('');
  const merged = [...new Set([...known, ...custom])].sort().join('');
  const flagsToken = merged || '0';
  const sectorType = (editorState.sectorType || '0').trim() || '0';

  return `${compatibilitySlot} ${flagsToken} ${sectorType}`;
}

function PropertyPanel() {
  const { currentAreaData, selectedRoom, updateRoom, deleteRoom, addExit, removeExit, loading } =
    useWorldBuilderStore();

  const [formData, setFormData] = useState({
    name: '',
    desc: '',
    rawRoomFlags: '0 0 0',
  });

  const [newExit, setNewExit] = useState({
    direction: 'north',
    targetVnum: '',
    doorType: 'none',
  });

  const [autoSaveEnabled, setAutoSaveEnabled] = useState(true);
  const [saveStatus, setSaveStatus] = useState('');
  const [roomFlagEditor, setRoomFlagEditor] = useState(() => parseRawRoomFlags('0 0 0'));

  const room = currentAreaData?.rooms.find((r) => r.vnum === selectedRoom);

  useEffect(() => {
    if (room) {
      const parsedFlags = parseRawRoomFlags(room.rawRoomFlags || '0 0 0');
      setFormData({
        name: room.name,
        desc: room.desc,
        rawRoomFlags: composeRawRoomFlags(parsedFlags),
      });
      setRoomFlagEditor(parsedFlags);
      setSaveStatus('');
    }
  }, [room]);

  // Auto-save when form data changes
  useEffect(() => {
    if (!autoSaveEnabled || !room) return;

    const timer = setTimeout(() => {
      if (JSON.stringify(formData) !== JSON.stringify({
        name: room.name,
        desc: room.desc,
        rawRoomFlags: room.rawRoomFlags || '0 0 0',
      })) {
        handleSaveRoom(true);
      }
    }, 1000);

    return () => clearTimeout(timer);
  }, [formData, autoSaveEnabled, room]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    if (name === 'rawRoomFlags') {
      const parsedFlags = parseRawRoomFlags(value);
      setRoomFlagEditor(parsedFlags);
      setFormData((prev) => ({ ...prev, [name]: composeRawRoomFlags(parsedFlags) }));
      return;
    }
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const updateFlagsFromEditor = (nextEditor) => {
    const normalizedEditor = {
      ...nextEditor,
      knownFlags: [...(nextEditor.knownFlags || [])],
    };
    setRoomFlagEditor(normalizedEditor);
    setFormData((prev) => ({
      ...prev,
      rawRoomFlags: composeRawRoomFlags(normalizedEditor),
    }));
  };

  const toggleKnownRoomFlag = (letter) => {
    const hasFlag = roomFlagEditor.knownFlags.includes(letter);
    const nextKnownFlags = hasFlag
      ? roomFlagEditor.knownFlags.filter((item) => item !== letter)
      : [...roomFlagEditor.knownFlags, letter].sort();

    updateFlagsFromEditor({
      ...roomFlagEditor,
      knownFlags: nextKnownFlags,
    });
  };

  const handleSaveRoom = (isAutoSave = false) => {
    if (room) {
      updateRoom(room.vnum, formData);
      if (!isAutoSave) {
        setSaveStatus('✓ Saved');
        setTimeout(() => setSaveStatus(''), 2000);
      }
    }
  };

  const handleDeleteRoom = () => {
    if (room && window.confirm(`Delete room ${selectedRoom}? This cannot be undone.`)) {
      deleteRoom(selectedRoom);
    }
  };

  const handleAddExit = () => {
    if (room && newExit.targetVnum) {
      const targetVnum = parseInt(newExit.targetVnum);
      
      // Check if target room exists
      if (!currentAreaData.rooms.find(r => r.vnum === targetVnum)) {
        alert(`Room ${targetVnum} does not exist in this area`);
        return;
      }

      addExit(room.vnum, {
        direction: newExit.direction,
        targetVnum: targetVnum,
        doorType: newExit.doorType,
      });
      setNewExit({ direction: 'north', targetVnum: '', doorType: 'none' });
    }
  };

  const handleRemoveExit = (direction) => {
    if (room) {
      removeExit(room.vnum, direction);
    }
  };

  const handleQuickNavigate = (direction) => {
    if (!room) return;
    const exit = room.exits?.find(ex => ex.direction === direction);
    if (exit) {
      // This will be handled by store's selectRoom
      useWorldBuilderStore.setState({ selectedRoom: exit.targetVnum });
    }
  };

  if (!room) {
    return (
      <div className="property-panel">
        <h2>⚙️ Properties</h2>
        <p className="text-muted mt-2">Select a room to edit its properties</p>
      </div>
    );
  }

  const directionOptions = ['north', 'south', 'east', 'west', 'up', 'down'];
  const roomVnums = currentAreaData?.rooms.map((r) => r.vnum) || [];
  const existingExits = (room.exits || []).map(e => e.direction);

  return (
    <div className="property-panel">
      <div className="property-header">
        <h2>⚙️ Room {room.vnum}</h2>
        <div style={{ fontSize: '12px', color: '#666' }}>
          {saveStatus && <span style={{ color: '#4caf50' }}>{saveStatus}</span>}
          {autoSaveEnabled && !saveStatus && <span style={{ color: '#999' }}>Auto-saving...</span>}
        </div>
      </div>

      <div className="property-content">
        {/* Quick Navigation */}
        <div className="card">
          <div className="card-header">Quick Navigation</div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', padding: '12px' }}>
            <button 
              onClick={() => handleQuickNavigate('north')}
              disabled={!existingExits.includes('north')}
              title="Go North"
              style={{ padding: '6px', fontSize: '12px' }}
            >
              ↑ N
            </button>
            <button 
              onClick={() => handleQuickNavigate('south')}
              disabled={!existingExits.includes('south')}
              title="Go South"
              style={{ padding: '6px', fontSize: '12px' }}
            >
              ↓ S
            </button>
            <button 
              onClick={() => handleQuickNavigate('west')}
              disabled={!existingExits.includes('west')}
              title="Go West"
              style={{ padding: '6px', fontSize: '12px' }}
            >
              ← W
            </button>
            <button 
              onClick={() => handleQuickNavigate('east')}
              disabled={!existingExits.includes('east')}
              title="Go East"
              style={{ padding: '6px', fontSize: '12px' }}
            >
              → E
            </button>
            <button 
              onClick={() => handleQuickNavigate('up')}
              disabled={!existingExits.includes('up')}
              title="Go Up"
              style={{ padding: '6px', fontSize: '12px' }}
            >
              ↗ U
            </button>
            <button 
              onClick={() => handleQuickNavigate('down')}
              disabled={!existingExits.includes('down')}
              title="Go Down"
              style={{ padding: '6px', fontSize: '12px' }}
            >
              ↙ D
            </button>
          </div>
        </div>

        {/* Room Info */}
        <div className="card">
          <div className="card-header">Room Details</div>
          <div style={{ padding: '12px' }}>
            <div style={{ marginBottom: '12px' }}>
              <label style={{ fontSize: '12px', color: '#666' }}>Name</label>
              <input
                type="text"
                name="name"
                placeholder="Room Name"
                value={formData.name}
                onChange={handleInputChange}
                style={{ width: '100%', padding: '6px', marginTop: '4px' }}
              />
            </div>

            <div style={{ marginBottom: '12px' }}>
              <label style={{ fontSize: '12px', color: '#666' }}>Description</label>
              <textarea
                name="desc"
                placeholder="Room Description"
                value={formData.desc}
                onChange={handleInputChange}
                rows={3}
                style={{ width: '100%', padding: '6px', marginTop: '4px', fontFamily: 'monospace' }}
              />
            </div>

            <div style={{ marginBottom: '12px' }}>
              <label style={{ fontSize: '12px', color: '#666' }}>Room Type (Sector)</label>
              <select
                value={roomFlagEditor.sectorType}
                onChange={(e) => updateFlagsFromEditor({ ...roomFlagEditor, sectorType: e.target.value })}
                style={{ width: '100%', padding: '6px', marginTop: '4px' }}
              >
                {SECTOR_OPTIONS.map((sector) => (
                  <option key={sector.value} value={sector.value}>
                    {sector.value}: {sector.label}
                  </option>
                ))}
              </select>
            </div>

            <div style={{ marginBottom: '12px' }}>
              <label style={{ fontSize: '12px', color: '#666' }}>Room Flags</label>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px', marginTop: '6px' }}>
                {ROOM_FLAG_OPTIONS.map((option) => (
                  <label key={option.letter} style={{ fontSize: '12px', color: '#333' }}>
                    <input
                      type="checkbox"
                      checked={roomFlagEditor.knownFlags.includes(option.letter)}
                      onChange={() => toggleKnownRoomFlag(option.letter)}
                      style={{ marginRight: '6px' }}
                    />
                    {option.label} ({option.letter})
                  </label>
                ))}
              </div>
            </div>

            <div style={{ marginBottom: '12px' }}>
              <label style={{ fontSize: '12px', color: '#666' }}>Extra Flag Letters (custom)</label>
              <input
                type="text"
                value={roomFlagEditor.customLetters}
                onChange={(e) => updateFlagsFromEditor({ ...roomFlagEditor, customLetters: e.target.value })}
                style={{ width: '100%', padding: '6px', marginTop: '4px', fontFamily: 'monospace' }}
                placeholder="Custom letters not in checklist"
              />
            </div>

            <div style={{ marginBottom: '12px' }}>
              <label style={{ fontSize: '12px', color: '#666' }}>Compatibility Slot (first value)</label>
              <input
                type="text"
                value={roomFlagEditor.compatibilitySlot}
                onChange={(e) => updateFlagsFromEditor({ ...roomFlagEditor, compatibilitySlot: e.target.value })}
                style={{ width: '100%', padding: '6px', marginTop: '4px', fontFamily: 'monospace' }}
                placeholder="Usually 0"
              />
            </div>

            <div style={{ marginBottom: '12px' }}>
              <label style={{ fontSize: '12px', color: '#666' }}>ROM Room Flags Line (advanced)</label>
              <input
                type="text"
                name="rawRoomFlags"
                placeholder="Example: 0 CDS 0"
                value={formData.rawRoomFlags}
                onChange={handleInputChange}
                style={{ width: '100%', padding: '6px', marginTop: '4px', fontFamily: 'monospace' }}
              />
              <div style={{ fontSize: '11px', color: '#888', marginTop: '4px' }}>
                Stored exactly as ROM room line after description (auto-generated from controls above).
              </div>
            </div>

            <div>
              <label style={{ fontSize: '12px', color: '#666' }}>
                <input 
                  type="checkbox" 
                  checked={autoSaveEnabled}
                  onChange={(e) => setAutoSaveEnabled(e.target.checked)}
                  style={{ marginRight: '4px' }}
                />
                Auto-save
              </label>
            </div>

            <div style={{ display: 'flex', gap: '8px', marginTop: '12px' }}>
              <button 
                onClick={() => handleSaveRoom()}
                disabled={loading}
                style={{ flex: 1, padding: '8px' }}
              >
                💾 Save
              </button>
              <button 
                onClick={handleDeleteRoom}
                disabled={loading}
                style={{ flex: 1, padding: '8px', background: '#ffebee', color: '#d32f2f' }}
              >
                🗑️ Delete
              </button>
            </div>
          </div>
        </div>

        {/* Exits Management */}
        <div className="card">
          <div className="card-header">Exits ({existingExits.length})</div>
          <div style={{ padding: '12px' }}>
            {existingExits.length > 0 && (
              <div style={{ marginBottom: '12px' }}>
                {(room.exits || []).map((exit) => (
                  <div 
                    key={exit.direction}
                    style={{
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      padding: '8px',
                      background: '#f5f5f5',
                      borderRadius: '4px',
                      marginBottom: '6px',
                      fontSize: '12px'
                    }}
                  >
                    <span>
                      <strong>{exit.direction.toUpperCase()}</strong> → {exit.targetVnum}
                    </span>
                    <button 
                      onClick={() => handleRemoveExit(exit.direction)}
                      style={{ padding: '4px 8px', fontSize: '11px' }}
                    >
                      Remove
                    </button>
                  </div>
                ))}
              </div>
            )}

            <div style={{ marginBottom: '12px' }}>
              <label style={{ fontSize: '12px', color: '#666' }}>Add Exit</label>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginTop: '8px' }}>
                <select 
                  value={newExit.direction} 
                  onChange={(e) => setNewExit(prev => ({ ...prev, direction: e.target.value }))}
                  disabled={directionOptions.every(d => existingExits.includes(d))}
                  style={{ padding: '6px' }}
                >
                  {directionOptions
                    .filter(d => !existingExits.includes(d))
                    .map(dir => (
                      <option key={dir} value={dir}>{dir}</option>
                    ))
                  }
                </select>
                <select 
                  value={newExit.targetVnum} 
                  onChange={(e) => setNewExit(prev => ({ ...prev, targetVnum: e.target.value }))}
                  style={{ padding: '6px' }}
                >
                  <option value="">Select room...</option>
                  {currentAreaData?.rooms
                    .filter(r => r.vnum !== room.vnum)
                    .sort((a, b) => a.vnum - b.vnum)
                    .map(r => (
                      <option key={r.vnum} value={r.vnum}>
                        {r.vnum}: {r.name}
                      </option>
                    ))
                  }
                </select>
              </div>
              <button 
                onClick={handleAddExit}
                disabled={!newExit.targetVnum || directionOptions.every(d => existingExits.includes(d))}
                style={{ width: '100%', padding: '8px', marginTop: '8px' }}
              >
                + Add Exit
              </button>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .property-panel {
          padding: 16px;
          height: 100%;
          overflow-y: auto;
          background: white;
        }

        .property-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 16px;
        }

        .property-header h2 {
          margin: 0;
          font-size: 18px;
        }

        .property-content {
          display: flex;
          flex-direction: column;
          gap: 12px;
        }

        .card {
          border: 1px solid #ddd;
          border-radius: 6px;
          overflow: hidden;
          background: white;
        }

        .card-header {
          background: #f5f5f5;
          padding: 8px 12px;
          font-weight: bold;
          font-size: 12px;
          border-bottom: 1px solid #ddd;
        }

        input,
        textarea,
        select {
          font-family: inherit;
          border: 1px solid #ddd;
          border-radius: 4px;
          font-size: 13px;
        }

        input:focus,
        textarea:focus,
        select:focus {
          outline: none;
          border-color: #667eea;
          box-shadow: 0 0 0 2px rgba(102, 126, 234, 0.1);
        }

        button {
          padding: 8px 12px;
          border: 1px solid #ddd;
          border-radius: 4px;
          background: white;
          cursor: pointer;
          font-size: 12px;
          font-weight: 500;
          transition: all 0.2s;
        }

        button:hover:not(:disabled) {
          background: #f5f5f5;
          border-color: #999;
        }

        button:disabled {
          opacity: 0.5;
          cursor: not-allowed;
        }

        .text-muted {
          color: #999;
        }

        .mt-2 {
          margin-top: 12px;
        }
